use std::io;

macro_rules! readln {
    () => {{
        use std::io;
        let mut buf = String::new();
        io::stdin().read_line(&mut buf).unwrap();
        buf.trim().to_string()
    }};
    ( $t:ty ) => {{
        let input = readln!();
        input.parse::<$t>().unwrap()
    }};
    ( $( $t:ty ),+ ) => {{
        let input = readln!();
        let mut input = input.split_whitespace();
        (
            $(
                input.next().unwrap().parse::<$t>().unwrap(),
            )+
        )
    }}
}

fn main() {
    let message = readln!();
    let message = message.chars().collect::<Vec<_>>();

    if message.len() % 2 == 0 {
        for index in 0..message.len() / 2 {
            print!("{}{}", message[message.len() / 2 - 1 - index], message[message.len() / 2 + index]);
        }
    } else {
        print!("{}", message[message.len() / 2]);
        for index in 0..message.len() / 2 {
            print!("{}{}", message[message.len() / 2 + 1 + index], message[message.len() / 2 - 1 - index]);
        }
    }

    println!();
}
